<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>2048</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 20px;
  }
  h1 { font-size: 3rem; color: #e2b714; }
  #ui {
    display: flex;
    align-items: center;
    gap: 24px;
  }
  #score-box {
    background: #16213e;
    border-radius: 8px;
    padding: 10px 24px;
    text-align: center;
  }
  #score-box label { font-size: 0.75rem; text-transform: uppercase; color: #888; }
  #score { font-size: 1.8rem; font-weight: bold; color: #e2b714; }
  #reset {
    background: #e2b714;
    color: #1a1a2e;
    border: none;
    border-radius: 8px;
    padding: 10px 24px;
    font-size: 1rem;
    font-weight: bold;
    cursor: pointer;
    transition: background 0.2s;
  }
  #reset:hover { background: #f0c830; }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 100px);
    grid-template-rows: repeat(4, 100px);
    gap: 10px;
    background: #0f3460;
    padding: 10px;
    border-radius: 12px;
  }
  .cell {
    width: 100px;
    height: 100px;
    border-radius: 8px;
    background: #16213e;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 2rem;
    font-weight: bold;
    color: #eee;
    transition: background 0.1s;
  }
  .cell[data-val="0"] { background: #16213e; color: transparent; }
  .cell[data-val="2"]    { background: #533483; }
  .cell[data-val="4"]    { background: #6b3fa0; }
  .cell[data-val="8"]    { background: #e84393; color: #fff; }
  .cell[data-val="16"]   { background: #e84343; }
  .cell[data-val="32"]   { background: #e86743; }
  .cell[data-val="64"]   { background: #e2b714; color: #1a1a2e; }
  .cell[data-val="128"]  { background: #a8d8ea; color: #1a1a2e; font-size: 1.6rem; }
  .cell[data-val="256"]  { background: #aa96da; color: #1a1a2e; font-size: 1.6rem; }
  .cell[data-val="512"]  { background: #fcbad3; color: #1a1a2e; font-size: 1.6rem; }
  .cell[data-val="1024"] { background: #ffffd2; color: #1a1a2e; font-size: 1.3rem; }
  .cell[data-val="2048"] { background: #e2b714; color: #1a1a2e; font-size: 1.3rem; }
</style>
</head>
<body>
<h1>2048</h1>
<div id="ui">
  <div id="score-box"><label>Score</label><div id="score">0</div></div>
  <button id="reset">New Game</button>
</div>
<div id="board"></div>
<script>
(function() {
  const SIZE = 4;
  let grid = [];
  let currentScore = 0;

  function emptyGrid() {
    return Array.from({length: SIZE}, () => Array(SIZE).fill(0));
  }

  function randomEmpty(g) {
    const empties = [];
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (g[r][c] === 0) empties.push([r, c]);
    if (!empties.length) return null;
    return empties[Math.floor(Math.random() * empties.length)];
  }

  function spawnTile(g) {
    const pos = randomEmpty(g);
    if (pos) g[pos[0]][pos[1]] = Math.random() < 0.9 ? 2 : 4;
  }

  function slideRow(row) {
    // Remove zeros
    let tiles = row.filter(v => v !== 0);
    let score = 0;
    // Merge adjacent equal tiles (at most once each)
    for (let i = 0; i < tiles.length - 1; i++) {
      if (tiles[i] === tiles[i + 1]) {
        tiles[i] *= 2;
        score += tiles[i];
        tiles.splice(i + 1, 1);
      }
    }
    // Pad with zeros
    while (tiles.length < SIZE) tiles.push(0);
    return { row: tiles, score };
  }

  function applyMove(direction) {
    let moved = false;
    let gained = 0;

    const rotated = rotateTo(direction, grid);
    for (let r = 0; r < SIZE; r++) {
      const result = slideRow(rotated[r]);
      for (let c = 0; c < SIZE; c++) {
        if (rotated[r][c] !== result.row[c]) moved = true;
      }
      rotated[r] = result.row;
      gained += result.score;
    }
    const restored = rotateFrom(direction, rotated);
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        grid[r][c] = restored[r][c];

    if (moved) {
      currentScore += gained;
      spawnTile(grid);
    }
    return moved;
  }

  // Rotate grid so that the desired direction becomes "slide left"
  function rotateTo(dir, g) {
    const copy = g.map(r => r.slice());
    if (dir === 'left') return copy;
    if (dir === 'right') return copy.map(r => r.slice().reverse());
    if (dir === 'up') return transpose(copy);
    if (dir === 'down') return transpose(copy).map(r => r.slice().reverse());
  }

  function rotateFrom(dir, g) {
    if (dir === 'left') return g;
    if (dir === 'right') return g.map(r => r.slice().reverse());
    if (dir === 'up') return transpose(g);
    if (dir === 'down') return transpose(g.map(r => r.slice().reverse()));
  }

  function transpose(g) {
    return Array.from({length: SIZE}, (_, r) =>
      Array.from({length: SIZE}, (__, c) => g[c][r]));
  }

  function render() {
    const board = document.getElementById('board');
    board.innerHTML = '';
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const val = grid[r][c];
        const cell = document.createElement('div');
        cell.className = 'cell';
        cell.dataset.val = val;
        cell.textContent = val === 0 ? '' : val;
        board.appendChild(cell);
      }
    }
    document.getElementById('score').textContent = currentScore;
  }

  function newGame() {
    grid = emptyGrid();
    currentScore = 0;
    spawnTile(grid);
    spawnTile(grid);
    render();
  }

  document.getElementById('reset').addEventListener('click', newGame);

  document.addEventListener('keydown', e => {
    const map = {
      ArrowLeft: 'left', ArrowRight: 'right',
      ArrowUp: 'up', ArrowDown: 'down'
    };
    if (map[e.key]) {
      e.preventDefault();
      applyMove(map[e.key]);
      render();
    }
  });

  window.game = {
    size: SIZE,
    reset() { newGame(); },
    move(dir) {
      const moved = applyMove(dir);
      render();
      return moved;
    },
    board() { return grid.map(r => r.slice()); },
    setBoard(arr) {
      for (let r = 0; r < SIZE; r++)
        for (let c = 0; c < SIZE; c++)
          grid[r][c] = arr[r][c];
      render();
    },
    score() { return currentScore; }
  };

  newGame();
})();
</script>
</body>
</html>
